FUNCTION    Sequence_ajustment         RETURN  PLS_INTEGER is

    Return_Status                       PLS_INTEGER;
    v_env_info_trace                    global_vars.env_info_trace_type;
    v_max_ind   PLS_INTEGER :=0;
    v_cur_ind   PLS_INTEGER :=0;



BEGIN
    v_env_info_trace.user_name      :=  global_vars.USER_NAME;
    v_env_info_trace.module_code    :=  global_vars.ML_ADMINISTRATION;
    v_env_info_trace.package_name   :=  $$PLSQL_UNIT;
    v_env_info_trace.function_name  :=  'Sequence_ajustment';
    v_env_info_trace.lang           :=  global_vars.LANG;

      dbms_output.put_line('SAQ2 ');
    select max (sequence_id) into v_max_ind
    from chargeback_reason_code;

    WHILE (v_max_ind > v_cur_ind)
    LOOP
        select chargeback_reason_code_x.NEXTVAL INTO v_cur_ind
        from dual;
    END LOOP;

        v_max_ind    :=0;
        v_cur_ind    :=0;

    select max (sequence_id) into v_max_ind
    from card_gen_counters;

    WHILE (v_max_ind > v_cur_ind)
    LOOP
        select card_gen_counters_x.NEXTVAL INTO v_cur_ind
        from dual;
    END LOOP;

        v_max_ind    :=0;
        v_cur_ind    :=0;
       dbms_output.put_line('SAQ3 ');
    select max (pcrd_card_prod_param_id) into v_max_ind
    from pcrd_card_prod_param;

    WHILE (v_max_ind > v_cur_ind)
    LOOP
        select pcrd_card_prod_param_x.NEXTVAL INTO v_cur_ind
        from dual;
    END LOOP;

        v_max_ind    :=0;
        v_cur_ind    :=0;

    select max (sequence_id) into v_max_ind
    from P7_SERVICES_SETUP;

    WHILE (v_max_ind > v_cur_ind)
    LOOP
        select P7_SERVICES_SETUP_x.NEXTVAL INTO v_cur_ind
        from dual;
    END LOOP;

        v_max_ind    :=0;
        v_cur_ind    :=0;

    select max (sequence_id) into v_max_ind
    from P7_SERVICES_criteria;

    WHILE (v_max_ind > v_cur_ind)
    LOOP
        select P7_SERVICES_criteria_x.NEXTVAL INTO v_cur_ind
        from dual;
    END LOOP;

        v_max_ind    :=0;
        v_cur_ind    :=0;

    select max (sequence_id) into v_max_ind
    from auth_ctrl_value_param;

    WHILE (v_max_ind > v_cur_ind)
    LOOP
        select auth_ctrl_value_param_x.NEXTVAL INTO v_cur_ind
        from dual;
    END LOOP;

        v_max_ind    :=0;
        v_cur_ind    :=0;

    select max (sequence_id) into v_max_ind
    from iss_posting_rules;

    WHILE (v_max_ind > v_cur_ind)
    LOOP
        select iss_posting_rules_x.NEXTVAL INTO v_cur_ind
        from dual;
    END LOOP;

        v_max_ind    :=0;
        v_cur_ind    :=0;

    select max (stop_renewal_criteria_id) into v_max_ind
    from stop_renewal_criteria;

    WHILE (v_max_ind > v_cur_ind)
    LOOP
        select stop_renewal_criteria_x.NEXTVAL INTO v_cur_ind
        from dual;
    END LOOP;

        v_max_ind    :=0;
        v_cur_ind    :=0;

    select max (rule_id) into v_max_ind
    from mer_exchange_matrix;

    WHILE (v_max_ind > v_cur_ind)
    LOOP
        select mer_exchange_matrix_x.NEXTVAL INTO v_cur_ind
        from dual;
    END LOOP;

    RETURN (declaration_cst.OK);

    EXCEPTION WHEN OTHERS
    THEN
        v_env_info_trace.user_message   :=  NULL;
        PCRD_GENERAL_TOOLS.PUT_TRACES (v_env_info_trace,$$PLSQL_LINE);
        RETURN (declaration_cst.ERROR);
END Sequence_ajustment;

----------------------------------------------------------------------------

FUNCTION    LOAD_BANK_PARAMETERS   (  p_business_date           IN                  DATE,
                                      p_bank_code               IN                  BANK.bank_code%TYPE,
                                      p_bank_wording            IN                   BANK.bank_name%TYPE,
                                      p_currency_code           IN                  CURRENCY_TABLE.currency_code%TYPE,
                                      p_currency_code_alpha     IN                  CURRENCY_TABLE.currency_code_alpha%TYPE,
                                      p_country_code            IN                  COUNTRY.country_code%TYPE,
                                      p_country_code_alpha       IN                   COUNTRY.iso_country_alpha%TYPE)
                                    RETURN  PLS_INTEGER IS

Return_Status                       PLS_INTEGER;
v_env_info_trace                    global_vars.env_info_trace_type;
v_sequence_id                       PLS_INTEGER;
v_index                               PLS_INTEGER;
v_count                                  PLS_INTEGER := 0;
v_region_code                         region.region_code%TYPE;
v_city_code                            city.city_code%TYPE;
BEGIN

    v_env_info_trace.user_name      :=  global_vars.USER_NAME;
    v_env_info_trace.module_code    :=  global_vars.ML_ADMINISTRATION;
    v_env_info_trace.package_name   :=  $$PLSQL_UNIT;
    v_env_info_trace.function_name  :=  'LOAD_BANK_PARAMETERS';
    v_env_info_trace.lang           :=  global_vars.LANG;



        select count(*)
        into v_count
         from   region
        where country_code =p_country_code;

            IF v_count='0'
            THEN

                v_region_code:='001';
                INSERT INTO REGION VALUES(p_country_code,v_region_code,'DEFAULT',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,30,NULL,'POWERCARD',NULL,NULL,NULL);
            ELSIF   v_count<>'0'
            THEN

                        select region_code
                        into v_region_code
                        from   region
                        where country_code =p_country_code
                        and rownum ='1' ;

            END IF;




        select count(*)
        into v_count
         from   city
        where region_code =v_region_code
        and country_code =p_country_code;
            IF v_count='0'
            THEN

                v_city_code:='00001';
            INSERT INTO CITY VALUES(p_country_code,v_city_code,'DEFAULT',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,v_region_code,'GMT',NULL,NULL,NULL,NULL);

            ELSIF   v_count<>'0'
            THEN

                        select city_code
                        into v_city_code
                        from   city
                        where region_code =v_region_code
                        and country_code =p_country_code
                        and rownum ='1' ;
            END IF;




    --***                   CENTER                          ***

    SELECT  MAX(TO_NUMBER(NVL(CENTER_CODE,0)))+ 1
    INTO    v_sequence_id
    FROM    CENTER
    WHERE CENTER_CODE <'21' ;

        INSERT INTO CENTER
        VALUES(v_sequence_id,'L',p_bank_wording,'01','Y',p_country_code,p_country_code_alpha,p_currency_code,p_currency_code_alpha,'SIAINT_BO',TO_DATE('2016-07-25 10:08:08', 'YYYY-MM-DD HH24:MI:SS'),NULL,NULL);

    --***                   BANK                          ***

        INSERT INTO BANK
        VALUES(p_bank_code,'BU',v_sequence_id,p_bank_wording,p_bank_wording,'Co-operative House','Huteau Lane',NULL,NULL,v_city_code,NULL,v_region_code,NULL,p_country_code,NULL,NULL,NULL,NULL,NULL,EMPTY_CLOB(),'P','N','N','Y','000001',NULL,NULL,0,TO_DATE('2003-02-24 00:00:00', 'YYYY-MM-DD HH24:MI:SS'),NULL,NULL,NULL,NULL,NULL,TO_DATE('2003-02-24 00:00:00', 'YYYY-MM-DD HH24:MI:SS'),NULL,p_currency_code,'O',10,'N',10,'N',24,'N',11,'N',10,'N',10,'N',NULL,0,'C',NULL,NULL,NULL,'A',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'POWERCARD',p_business_date,'POWERCARD',p_business_date );

    --***                   BANK_ADDENDUM                          ***

        INSERT INTO  BANK_ADDENDUM
        VALUES(p_bank_code,p_bank_code,'N',NULL,NULL,NULL,'N',NULL,'0000100000',NULL,'N',NULL,NULL,NULL,'G',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'N','N','N','Y',NULL,NULL,'N',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'User02',TO_DATE('2016-07-25 10:09:07', 'YYYY-MM-DD HH24:MI:SS'),NULL,NULL);



        INSERT INTO PCARD_TASKS_EXEC_GROUP_BANK
        VALUES('DFLGRP',p_bank_code,'firstUser',TO_DATE('2024-02-28 16:15:37', 'YYYY-MM-DD HH24:MI:SS'),'firstUser',TO_DATE('2024-02-28 17:16:38', 'YYYY-MM-DD HH24:MI:SS'));
        RETURN (declaration_cst.OK);


    EXCEPTION WHEN OTHERS
    THEN
        v_env_info_trace.user_message   :=  NULL;
        PCRD_GENERAL_TOOLS.PUT_TRACES (v_env_info_trace,$$PLSQL_LINE);
        RETURN (declaration_cst.ERROR);
END LOAD_BANK_PARAMETERS;


